 7→export default function ThreePreviewPanel({ project, activeFloorId, className = '' }) {
 8→  const viewportRef = useRef(null);
 9→  const containerRef = useRef(null);
10→  const resizeObserverRef = useRef(null);
11→  const sceneDescriptor = useMemo(() => buildPreviewScene(project, {
12→    activeFloorId,
13→    visibleFloorIds: activeFloorId ? [activeFloorId] : [],
14→  }), [project, activeFloorId]);
15→
16→  const activeFloor = (project?.floors || []).find((floor) => floor.id === activeFloorId) || null;
17→  const activeFloorDescriptor = sceneDescriptor.floors.find((floor) => floor.floorId === activeFloorId) || null;
18→  const visibleCount = activeFloorDescriptor?.objects.length || 0;
19→
20→  useEffect(() => {
21→    if (!containerRef.current) return undefined;
22→
23→    const viewport = createPreviewViewport(containerRef.current);
24→    viewportRef.current = viewport;
25→
26→    if ('ResizeObserver' in window) {
27→      const observer = new ResizeObserver(() => {
28→        viewport.resize();
29→      });
30→      observer.observe(containerRef.current);
31→      resizeObserverRef.current = observer;
32→    }
33→
34→    viewport.resize();
35→
36→    return () => {
37→      resizeObserverRef.current?.disconnect?.();
38→      resizeObserverRef.current = null;
39→      viewport.dispose();
40→      viewportRef.current = null;
41→    };
42→  }, []);
43→
44→  useEffect(() => {
45→    const viewport = viewportRef.current;
46→    if (!viewport) return;
47→
48→    const root = buildPreviewObjectRoot(sceneDescriptor, viewport.materialPalette);
49→    viewport.setWorld(root, sceneDescriptor.bounds, sceneDescriptor.groundLevel);
50→  }, [sceneDescriptor]);
51→
52→  return (
53→    <section className={`${styles.panel} ${className}`}>
54→      <div className={styles.header}>
55→        <div className={styles.titleGroup}>
56→          <span className={styles.eyebrow}>3D Preview</span>
57→          <span className={styles.title}>
58→            {activeFloor ? `${activeFloor.name} · ${visibleCount} objects` : 'No active floor'}
59→          </span>
60→        </div>
61→        <div className={styles.actions}>
62→          <button
63→            type="button"
64→            className={styles.button}
65→            onClick={() => viewportRef.current?.resetView()}
66→          >
67→            Reset View
68→          </button>
69→        </div>
70→      </div>
71→
72→      <div className={styles.viewportWrap}>
73→        <div ref={containerRef} className={styles.viewport} />
74→        {!sceneDescriptor.hasVisibleObjects && (
75→          <div className={styles.emptyState}>
76→            <span className={styles.emptyTitle}>Scene Empty</span>
77→            <span className={styles.emptyBody}>
78→              Add walls, slab, columns, beams, stairs, doors, or windows to populate the read-only preview.
79→            </span>
80→          </div>
81→        )}
82→      </div>
83→
84→      <div className={styles.footer}>
85→        <span>Orbit: drag · Pan: right drag · Zoom: wheel</span>
86→        <span>Perspective preview, future-ready for presets and floor visibility.</span>
87→      </div>
88→    </section>
89→  );
90→}
