101→function AppInner() {
102→  const { project, isDirty, dispatch } = useProject();
103→  const [showLoadModal, setShowLoadModal] = useState(false);
104→  const [savedProjects, setSavedProjects] = useState([]);
105→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
106→  const [isPropertiesCollapsed, setIsPropertiesCollapsed] = useState(false);
107→
108→  useAutosave(project, isDirty, dispatch);
109→
110→  // beforeunload warning
111→  useEffect(() => {
112→    const handler = (e) => {
113→      if (isDirty) {
114→        e.preventDefault();
115→        e.returnValue = '';
116→      }
117→    };
118→    window.addEventListener('beforeunload', handler);
119→    return () => window.removeEventListener('beforeunload', handler);
120→  }, [isDirty]);
121→
122→  const handleNew = useCallback(() => {
123→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
124→    dispatch({ type: 'PROJECT_NEW', project: createProject() });
125→  }, [isDirty, dispatch]);
126→
127→  const handleSave = useCallback(async () => {
128→    await saveProject(project);
129→    dispatch({ type: 'MARK_SAVED' });
130→  }, [project, dispatch]);
131→
132→  // Ctrl+S save
133→  useEffect(() => {
134→    const handler = (e) => {
135→      if (isTypingTarget(e.target)) return;
136→      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
137→        e.preventDefault();
138→        handleSave();
139→      }
140→    };
141→    window.addEventListener('keydown', handler);
142→    return () => window.removeEventListener('keydown', handler);
143→  }, [handleSave]);
144→
145→  const handleLoadClick = useCallback(async () => {
146→    setSavedProjects(await listProjects());
147→    setShowLoadModal(true);
148→  }, []);
149→
150→  const handleLoad = useCallback(async (id) => {
151→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
152→    try {
153→      const { project: loaded, savedAt } = await loadProject(id);
154→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
155→      setShowLoadModal(false);
156→    } catch (err) {
157→      alert('Failed to load project: ' + err.message);
158→    }
159→  }, [isDirty, dispatch]);
